    // Define events
    event CropIssued(uint256 cropID, string cropName, uint256 amount, uint256 value, address farmer);
    event CropTransferred(address from, address to, uint256 cropID, uint256 value);

    // Define struct for crop
    struct Crop {
        string cropName;
        uint256 amount;
        uint256 value;
        address farmer;
        bool exists;
    }

    // Define mapping of crop IDs to crops
    mapping(uint256 => Crop) public crops;

    // Define counter for crop IDs
    uint256 public cropIDCounter;

    // Define constructor to initialize contract and ERC721 token
    constructor() ERC721("Farming Crop NFT", "FARMCRP") {}

    // Define function for farmer to issue NFT of crops to primary buyer
    function issueCropNFT(string memory _cropName, uint256 _amount, uint256 _value) public returns (uint256) {
        // Increment crop ID counter
        cropIDCounter++;

        // Create new crop struct
        Crop memory newCrop = Crop({
            cropName: _cropName,
            amount: _amount,
            value: _value,
            farmer: msg.sender,
            exists: true
        });

        // Add new crop to mapping
        crops[cropIDCounter] = newCrop;

        // Mint NFT to farmer
        _mint(msg.sender, cropIDCounter);

        // Emit event for new crop issuance
        emit CropIssued(cropIDCounter, _cropName, _amount, _value, msg.sender);

        // Return crop ID
        return cropIDCounter;
    }

    // Define function for primary buyer to purchase NFT of crops from farmer
    function purchaseCropNFT(uint256 _cropID) public payable {
        // Ensure crop exists and is owned by farmer
        require(crops[_cropID].exists, "Crop does not exist");
        require(ownerOf(_cropID) == crops[_cropID].farmer, "Crop is not owned by farmer");

        // Ensure buyer sends enough value
        require(msg.value >= crops[_cropID].value, "Insufficient value sent");

        // Transfer ownership of crop NFT to buyer
        _transfer(crops[_cropID].farmer, msg.sender, _cropID);

        // Emit event for crop transfer
        emit CropTransferred(crops[_cropID].farmer, msg.sender, _cropID, crops[_cropID].value);
    }

    // Define function for secondary buyer to purchase NFT of crops from primary buyer on marketplace
    function buyCropNFTOnMarketplace(uint256 _cropID) public payable {
        // Ensure crop exists and is owned by primary buyer
        require(crops[_cropID].exists, "Crop does not exist");
        require(ownerOf(_cropID) != crops[_cropID].farmer, "Crop is owned by farmer");

        // Ensure buyer sends enough value
        require(msg.value >= crops[_cropID].value, "Insufficient value sent");

        // Calculate fees for primary buyer and owner
        uint256 primaryBuyerFee = (crops[_cropID].value.mul(5)).div(100);
    uint256 ownerFee = (crops[_cropID].value.mul(1)).div(100);

    // Transfer fees to contract owner and primary buyer
    payable(owner()).transfer(ownerFee);
    payable(crops[_cropID].farmer).transfer(primaryBuyerFee);

    // Transfer ownership of crop NFT to buyer
    _transfer(ownerOf(_cropID), msg.sender, _cropID);

    // Emit event for crop transfer
    emit CropTransferred(ownerOf(_cropID), msg.sender, _cropID, crops[_cropID].value);
}

// Define function for farmer to destroy NFT of crops when they stop farming
function destroyCropNFT(uint256 _cropID) public onlyOwner {
    // Ensure crop exists and is owned by farmer
    require(crops[_cropID].exists, "Crop does not exist");
    require(ownerOf(_cropID) == crops[_cropID].farmer, "Crop is not owned by farmer");

    // Burn NFT
    _burn(_cropID);

    // Emit event for crop destruction
    emit CropTransferred(crops[_cropID].farmer, address(0), _cropID, crops[_cropID].value);

    // Delete crop from mapping
    delete crops[_cropID];
}

// Override _beforeTokenTransfer function to ensure only primary buyer can transfer NFT of crops
function _beforeTokenTransfer(address from, address to, uint256 tokenId) internal override {
    super._beforeTokenTransfer(from, to, tokenId);

    if (from != address(0) && to != address(0)) {
        require(crops[tokenId].exists, "Crop does not exist");
        require(ownerOf(tokenId) != crops[tokenId].farmer, "Crop is owned by farmer");
    }
}
}
